import requests
import json
from datetime import datetime, timedelta

API_KEY = "sk-qDHmOX32qh6xAKJbeilhC6pIzrLNfUJyiMTaowGr2RA"
BASE_URL = "https://qveris.ai/api/v1"

def call_tool(tool_id, params):
    """调用 QVeris 工具"""
    url = f"{BASE_URL}/invoke"
    headers = {
        "Authorization": f"Bearer {API_KEY}",
        "Content-Type": "application/json"
    }
    data = {
        "tool_id": tool_id,
        "params": params
    }

    try:
        resp = requests.post(url, headers=headers, json=data, timeout=30)
        resp.raise_for_status()
        return resp.json()
    except Exception as e:
        return {"error": str(e)}

# 获取昨天的日期（周五收盘数据）
yesterday = (datetime.now() - timedelta(days=1)).strftime("%Y-%m-%d")

print("=" * 70)
print("📊 盘后投研报告 -", datetime.now().strftime("%Y-%m-%d %H:%M"))
print("=" * 70)

# 1. 获取主要指数实时行情
print("\n【1】主要指数收盘")
print("-" * 50)
result = call_tool("ths_ifind.real_time_quotation.v1", {
    "codes": "000001.SH,399001.SZ,399006.SZ,000300.SH",
    "indicators": "all"
})

if "result" in result:
    data = result["result"]
    if isinstance(data, list):
        for item in data:
            if isinstance(item, dict):
                code = item.get("代码", item.get("code", ""))
                name = item.get("名称", item.get("name", ""))
                price = item.get("最新价", item.get("close", 0))
                change_pct = item.get("涨跌幅", item.get("pct_change", 0))
                volume = item.get("成交量", item.get("volume", 0))
                amount = item.get("成交额", item.get("amount", 0))

                print(f"{name} ({code})")
                print(f"  价格: {price:.2f} | 涨跌: {change_pct:+.2f}%")
                if amount and isinstance(amount, (int, float)):
                    print(f"  成交额: {amount/100000000:.2f}亿")
                print()
elif "error" in result:
    print(f"获取失败: {result['error']}")

# 2. 获取北向资金
print("\n【2】北向资金流向")
print("-" * 50)
result = call_tool("ths_ifind.hk_connect_stats.v1", {
    "sdate": yesterday,
    "edate": yesterday,
    "zq": "day"
})

if "result" in result:
    data = result["result"]
    if isinstance(data, list) and len(data) > 0:
        for item in data[:4]:  # 显示前4条
            if isinstance(item, dict):
                date = item.get("日期", item.get("date", ""))
                channel = item.get("类型", item.get("channel", ""))
                net_buy = item.get("净买入额", item.get("net_buy", 0))
                volume = item.get("成交金额", item.get("volume", 0))

                if net_buy and isinstance(net_buy, (int, float)):
                    print(f"{date} | {channel}")
                    print(f"  净买入: {net_buy/100000000:.2f}亿")
                    print()
elif "error" in result:
    print(f"获取失败: {result['error']}")

# 3. 获取市场资金流
print("\n【3】市场资金流")
print("-" * 50)
result = call_tool("ths_ifind.money_flow.v1", {
    "scope": "market",
    "codes": "000985.CSI",
    "startdate": yesterday,
    "enddate": yesterday
})

if "result" in result:
    data = result["result"]
    if isinstance(data, list) and len(data) > 0:
        item = data[0]
        if isinstance(item, dict):
            main_flow = item.get("主力净流入", item.get("main_net_inflow", 0))
            large_flow = item.get("超大单净流入", item.get("super_large_net_inflow", 0))
            medium_flow = item.get("中单净流入", item.get("medium_net_inflow", 0))
            small_flow = item.get("小单净流入", item.get("small_net_inflow", 0))

            if isinstance(main_flow, (int, float)):
                print(f"主力净流入: {main_flow/100000000:.2f}亿")
            if isinstance(large_flow, (int, float)):
                print(f"超大单净流入: {large_flow/100000000:.2f}亿")
            if isinstance(medium_flow, (int, float)):
                print(f"中单净流入: {medium_flow/100000000:.2f}亿")
            if isinstance(small_flow, (int, float)):
                print(f"小单净流入: {small_flow/100000000:.2f}亿")
elif "error" in result:
    print(f"获取失败: {result['error']}")

print("\n" + "=" * 70)
print("报告生成完成")
print("=" * 70)
SCRIPT

